-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 053 — Git desde Cero · M5: Recuperación y diagnóstico
-- ═══════════════════════════════════════════════════════════════════
-- Unidad 5 del temario (bloques 30-34 + Práctica 5). Cubre: restaurar
-- cambios no confirmados (restore), deshacer un commit en público
-- (revert), mover el historial (reset --soft/--mixed/--hard + la tabla
-- imprescindible), recuperar trabajo con reflog, y encontrar el commit
-- que introdujo un error con bisect. Práctica: elegir la operación
-- segura ante una incidencia en producción.
-- Precisiones vinculantes: revert para lo PÚBLICO (conserva historial),
-- reset para lo LOCAL (reescribe); reflog es LOCAL, no es respaldo y sus
-- entradas expiran; --hard descarta trabajo (irrecuperable salvo reflog).
-- Curso language = bash → práctica por regex + mockOutput.
-- Curso is_published = false: nada visible hasta el flip final (056).
-- Idempotente. Ejecutar DESPUÉS de 048.
-- ═══════════════════════════════════════════════════════════════════

delete from public.lessons
where module_id = (
  select m.id from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'git-desde-cero' and m.slug = 'm05-recuperacion'
);

insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m05-l01-restore',   'Restaurar cambios no confirmados',    'leccion',  20, 1),
       ('m05-l02-revert',    'Deshacer un commit con revert',       'leccion',  20, 2),
       ('m05-l03-reset',     'Mover el historial con reset',        'leccion',  20, 3),
       ('m05-l04-reflog',    'Recuperar trabajo con reflog',        'leccion',  20, 4),
       ('m05-l05-bisect',    'Encontrar el error con bisect',       'leccion',  20, 5),
       ('m05-l06-practica',  'Práctica: incidente en producción',   'practica', 20, 6),
       ('m05-x01-examen',    'Examen: Recuperación y diagnóstico',  'examen',   40, 7)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'git-desde-cero' and m.slug = 'm05-recuperacion';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · Restaurar cambios no confirmados
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Deshacer, según dónde esté el cambio","body":"Equivocarse es normal; Git tiene una herramienta distinta para cada tipo de arrepentimiento, y la clave es DÓNDE está el cambio que quieres deshacer. Empecemos por lo más leve: cambios que aún NO commiteaste. Editaste un archivo, no te gustó, y quieres volver a como estaba en el último commit. git restore archivo descarta los cambios NO preparados de ese archivo, devolviéndolo a como estaba en el último commit. Y si ya lo habías preparado (git add) y quieres solo SACARLO del área de preparación sin perder el cambio, git restore --staged archivo (que ya viste en el módulo 2) lo devuelve de 'preparado' a 'modificado'. Dos usos de restore: sin --staged descarta el cambio; con --staged solo lo desprepara."}$j$),
  (2, 'ejemplo_codigo', $j${"title":"Los dos restore","code":"# Descartar cambios NO preparados (volver al ultimo commit)\ngit restore config.py\n\n# Solo SACAR del staging, conservando el cambio\ngit restore --staged config.py\n\n# git status suele recordarte estas opciones en su salida","caption":"restore archivo = descartar el cambio (¡irreversible!). restore --staged archivo = despreparar, sin perder nada.","result":{"columns":["EFECTO"],"rows":[["restore config.py → cambios descartados, archivo como el último commit"],["restore --staged config.py → sale del staging, el cambio sigue ahí"]],"note":"La diferencia es enorme: sin --staged, el cambio se PIERDE (Git no lo tenía guardado en ningún commit). Con --staged, solo cambia de estado. Git diferencia además restaurar desde HEAD, desde el índice o desde otra referencia."}}$j$),
  (3, 'texto', $j${"title":"⚠ El riesgo: restore sin --staged no tiene vuelta","body":"Cuidado con git restore archivo (sin --staged): descarta tus cambios no confirmados de forma DEFINITIVA. Como esos cambios nunca estuvieron en un commit, Git no tiene ninguna copia de ellos — una vez descartados, se fueron para siempre (ni siquiera el reflog de la lección 4 los salva, porque nunca fueron commit). Es el equivalente a cerrar un documento sin guardar: lo que no se guardó, no se recupera. La disciplina profesional antes de cualquier operación que descarte trabajo: mira primero git status (¿qué voy a perder exactamente?) y, si dudas, hasta git diff (¿qué decía ese cambio?). Confirmar el estado antes de restaurar convierte un 'ups, perdí una hora de trabajo' en 'sí, esto era lo que quería descartar'. Deshacer lo no confirmado es rápido y útil, pero es una puerta de un solo sentido: se cruza con los ojos abiertos."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Editaste config.py, no te gustó el cambio y AÚN no lo commiteaste. ¿Cómo lo devuelves a como estaba en el último commit?","options":["git reset --hard","git restore config.py — descarta el cambio no confirmado de ese archivo, dejándolo como el último commit","git revert config.py","git commit --amend"],"correctIndex":1,"feedback":{"correct":"Correcto. restore (sin --staged) descarta el cambio no preparado y devuelve el archivo al último commit.","incorrect":"git restore archivo descarta los cambios no confirmados de ese archivo. revert es para commits ya hechos; reset mueve el historial."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es la diferencia entre git restore archivo y git restore --staged archivo?","options":["Son idénticos","Sin --staged DESCARTA el cambio (lo pierde); con --staged solo lo SACA del área de preparación, conservándolo (de 'preparado' a 'modificado')","--staged borra el archivo","restore siempre requiere --staged"],"correctIndex":1,"feedback":{"correct":"Correcto. Sin --staged = descartar (peligroso); con --staged = despreparar (seguro). El primero pierde el trabajo.","incorrect":"restore archivo descarta el cambio; restore --staged archivo solo lo desprepara sin perderlo. La diferencia es total."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué git restore archivo (sin --staged) es una 'puerta de un solo sentido'?","options":["Porque cierra el repositorio","Porque descarta cambios que NUNCA estuvieron en un commit: Git no tiene copia de ellos, así que se pierden para siempre (ni el reflog los salva) — se confirma con git status/diff antes de usarlo","Porque bloquea la rama","Porque no se puede volver a editar el archivo"],"correctIndex":1,"feedback":{"correct":"Correcto. Lo no commiteado no tiene respaldo en Git: descartarlo es definitivo. Mira status/diff antes.","incorrect":"restore descarta trabajo no confirmado, del que Git no guarda copia: es irreversible. Por eso se revisa el estado primero."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Restaurar lo no confirmado","points":["restore es para cambios que AÚN no commiteaste; la clave siempre es DÓNDE está el cambio.","git restore archivo DESCARTA el cambio no preparado (lo devuelve al último commit).","git restore --staged archivo solo lo SACA del staging, sin perderlo (de 'preparado' a 'modificado').","⚠ restore sin --staged es IRREVERSIBLE: lo no confirmado no tiene copia en Git (ni el reflog lo salva).","Disciplina: mira git status (y diff) antes de descartar — cruza la puerta de un solo sentido con los ojos abiertos."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-l01-restore';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Deshacer un commit con revert
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Deshacer sin borrar la historia","body":"Subimos un nivel: el cambio que quieres deshacer YA es un commit, y peor, ya lo COMPARTISTE (está en main, otros lo tienen). No puedes borrarlo de la historia sin romper la regla de oro. La solución elegante es git revert HASH: en lugar de borrar el commit malo, CREA UN COMMIT NUEVO que deshace exactamente lo que aquel hizo — si el commit malo agregó tres líneas, el revert crea un commit que las quita; si borró algo, el revert lo restaura. El historial CRECE (no se encoge): quedan el commit original Y el commit que lo revierte, ambos visibles. Es 'deshacer hacia adelante': la corrección es en sí un cambio registrado, honesto, que cualquiera puede ver y entender."}$j$),
  (2, 'ejemplo_codigo', $j${"title":"Revertir un commit publicado","code":"# El commit a3f9c1d rompio el calculo de facturas, y ya esta en main\ngit log --oneline\n#   a3f9c1d Cambia la formula del total   <- este rompio todo\n#   b2c3d4e Agrega el modulo de facturas\n\n# Deshacerlo con un commit nuevo (no borra la historia)\ngit revert a3f9c1d","caption":"revert crea un commit inverso: el historial crece, el commit malo sigue visible, y su efecto queda anulado.","result":{"columns":["git log --oneline (después)"],"rows":[["9z8y7x6 Revert \"Cambia la formula del total\""],["a3f9c1d Cambia la formula del total"],["b2c3d4e Agrega el modulo de facturas"]],"note":"El commit original (a3f9c1d) SIGUE ahí; encima aparece el revert que lo deshace. Nadie tuvo que reescribir la historia: la corrección es un commit más, seguro de compartir. Git suele proponerte el mensaje 'Revert ...' automáticamente."}}$j$),
  (3, 'texto', $j${"title":"Por qué revert es el rey de lo público","body":"revert es LA herramienta para deshacer en un historial compartido, y la razón es justo que NO reescribe la historia: solo agrega un commit. Como no toca los commits que otros ya tienen, no hay choque de historiales, no se rompe nada para el equipo — todos simplemente reciben un commit más (el que deshace). Por eso es la respuesta correcta cuando un cambio malo llegó a producción: revert lo anula de forma segura, con un registro claro de qué se deshizo y cuándo. Compara con lo que verás en la próxima lección: reset SÍ reescribe/mueve la historia, y por eso es solo para lo local. La regla que las certificaciones adoran: para deshacer algo YA PÚBLICO, revert (conserva la historia); para reorganizar algo LOCAL que nadie ha visto, reset. Elegir mal —usar reset sobre lo público— es exactamente romper la regla de oro."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué hace git revert HASH?","options":["Borra el commit del historial","CREA UN COMMIT NUEVO que deshace exactamente lo que hizo el commit indicado — el historial crece, el commit original sigue visible","Mueve el puntero de la rama hacia atrás","Descarta cambios sin confirmar"],"correctIndex":1,"feedback":{"correct":"Correcto. revert deshace 'hacia adelante': un commit inverso. Nada se borra de la historia.","incorrect":"revert no borra: agrega un commit que anula al malo. El original permanece; la historia crece."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Un commit que ya está en main (compartido) rompió producción. ¿Cuál es la forma SEGURA de deshacerlo?","options":["Borrarlo del historial con reset","git revert HASH: crea un commit que lo anula sin reescribir la historia — como no toca lo que otros ya tienen, no rompe nada para el equipo","git restore","Editar el commit con --amend"],"correctIndex":1,"feedback":{"correct":"Correcto. En un historial compartido se usa revert: deshace con un commit nuevo, sin tocar la historia ajena.","incorrect":"Sobre algo público, revert. reset o amend reescribirían una historia que el equipo ya tiene: la regla de oro rota."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"La regla que decide entre revert y reset:","options":["revert es más moderno","Para deshacer algo YA PÚBLICO → revert (conserva la historia, solo agrega un commit); para reorganizar algo LOCAL que nadie ha visto → reset (reescribe la historia)","Siempre reset","Siempre revert"],"correctIndex":1,"feedback":{"correct":"Correcto. Público = revert (no reescribe); local = reset (reescribe). Usar reset sobre lo público rompe la regla de oro.","incorrect":"revert para lo compartido (no toca la historia); reset para lo local. La clave es si otros ya tienen esos commits."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — revert","points":["git revert HASH crea un COMMIT NUEVO que deshace lo que hizo el commit indicado: 'deshacer hacia adelante'.","El historial CRECE: el commit original sigue visible y encima queda el que lo revierte.","Como NO reescribe la historia, es seguro en repositorios compartidos: no rompe nada para el equipo.","Es la herramienta para deshacer algo que ya llegó a producción / a main.","Regla: PÚBLICO → revert (conserva); LOCAL → reset (reescribe). reset sobre lo público = romper la regla de oro."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-l02-revert';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Mover el historial con reset (+ la tabla imprescindible)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Mover el puntero hacia atrás","body":"git reset es la herramienta para reorganizar tu historia LOCAL: mueve el puntero de la rama (y con él HEAD) a un commit anterior, 'deshaciendo' los commits posteriores. Por ejemplo, hiciste tres commits que en realidad deberían ser uno, o commiteaste algo que aún no querías: reset te lleva de vuelta a antes de ellos. Pero reset tiene TRES MODOS, y la diferencia entre ellos —qué pasa con tu trabajo al retroceder— es lo que hay que entender para no perder nada por accidente. La pregunta que los distingue: al mover el puntero atrás, ¿qué hago con los cambios de los commits que estoy deshaciendo? ¿los guardo preparados, los guardo sin preparar, o los tiro?"}$j$),
  (2, 'texto', $j${"title":"Los tres modos: soft, mixed, hard","body":"reset --SOFT mueve el puntero atrás pero CONSERVA todo: los cambios de los commits deshechos quedan PREPARADOS (staged), listos para volver a commitearse. Úsalo para rehacer commits: 'deshago estos tres y los vuelvo a armar como uno'. reset --MIXED (el modo por defecto, si no pones nada) mueve el puntero y conserva los cambios, pero SIN preparar (quedan como modificados en tu directorio): 'deshago los commits y también el add, pero mi trabajo sigue ahí'. reset --HARD mueve el puntero y DESCARTA TODO: los commits deshechos y sus cambios desaparecen del directorio de trabajo. Es el único de los tres que PIERDE trabajo — potente y peligroso. La constante: los tres mueven el puntero (deshacen commits); lo que cambia es el destino de los cambios: preparados (soft), sin preparar (mixed), o borrados (hard)."}$j$),
  (3, 'ejemplo_codigo', $j${"title":"La tabla imprescindible","code":"# Deshacer el ultimo commit de tres formas distintas:\ngit reset --soft  HEAD~1   # commit deshecho; cambios PREPARADOS\ngit reset --mixed HEAD~1   # commit deshecho; cambios SIN preparar (por defecto)\ngit reset --hard  HEAD~1   # commit deshecho; cambios BORRADOS\n\n# (HEAD~1 = 'un commit antes del actual')","caption":"Los tres mueven HEAD un commit atrás; se diferencian en qué hacen con tu trabajo.","result":{"columns":["MODO","HISTORIAL","STAGING","ARCHIVOS"],"rows":[["--soft","mueve HEAD","conserva (preparado)","conserva"],["--mixed","mueve HEAD","limpia (sin preparar)","conserva"],["--hard","mueve HEAD","limpia","BORRA"],["revert","conserva (+commit)","—","aplica el inverso"]],"note":"Los tres reset mueven el puntero; solo --hard destruye trabajo. Se incluye revert en la tabla para el contraste: revert NO mueve el puntero — agrega un commit inverso. reset reescribe (local); revert conserva (público)."}}$j$),
  (4, 'texto', $j${"title":"⚠ --hard y la regla de oro, juntas","body":"Dos advertencias que hacen a reset la herramienta más filosa del módulo. UNA: --hard DESCARTA trabajo. Si entre los commits que borras había cambios que no querías perder, se van — aunque, como eran COMMITS, el reflog de la próxima lección todavía puede rescatarlos (a diferencia de restore, que borra lo que nunca fue commit). Aun así, --hard nunca se usa a la ligera: mira git status antes, y pregúntate si hay algo sin guardar en otro lado. DOS: reset REESCRIBE/MUEVE la historia, así que NUNCA se usa sobre commits ya PÚBLICOS que otros tienen — mover el puntero atrás en una rama compartida deja al equipo con historiales divergentes. reset es para tu historia LOCAL, privada, no publicada. Para deshacer algo público existe revert (lección anterior). La frase que resume el módulo: reset reorganiza lo tuyo antes de compartirlo; revert corrige lo que ya se compartió."}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué hacen en común los tres modos de git reset, y qué los diferencia?","options":["Todos borran archivos; se diferencian en la velocidad","Los tres MUEVEN el puntero de la rama a un commit anterior (deshacen commits); se diferencian en qué pasa con los cambios: --soft los deja preparados, --mixed sin preparar, --hard los BORRA","Todos crean un commit nuevo","Se diferencian solo en el mensaje"],"correctIndex":1,"feedback":{"correct":"Correcto. Constante: mover el puntero atrás. Variable: el destino del trabajo (preparado/sin preparar/borrado).","incorrect":"Los tres mueven el puntero (deshacen commits). La diferencia es qué hacen con los cambios: soft (preparados), mixed (sin preparar), hard (borrados)."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Quieres deshacer tus últimos tres commits LOCALES para rearmarlos como uno solo, SIN perder ni una línea de trabajo. ¿Qué modo?","options":["git reset --hard","git reset --soft: mueve el puntero atrás y deja todos los cambios PREPARADOS, listos para volver a commitearse juntos","git reset --mixed y luego --hard","git revert"],"correctIndex":1,"feedback":{"correct":"Correcto. --soft conserva todo preparado: perfecto para recombinar commits locales sin perder trabajo.","incorrect":"--soft deja los cambios listos (preparados) para rehacer el commit. --hard los borraría; revert no sirve para reorganizar local."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es el ÚNICO modo de reset que puede hacerte perder trabajo, y qué precaución exige?","options":["--soft; hacer backup","--hard: DESCARTA los cambios de los commits deshechos del directorio de trabajo — mira git status antes y asegúrate de no tener trabajo sin guardar (el reflog aún rescata lo que fue commit, pero no lo demás)","--mixed; reiniciar","Ninguno pierde trabajo"],"correctIndex":1,"feedback":{"correct":"Correcto. --hard es el filoso: borra trabajo. soft y mixed lo conservan. Revisa el estado antes de usarlo.","incorrect":"Solo --hard descarta trabajo (soft y mixed lo conservan). Antes de usarlo: git status y verificar que no haya nada que perder."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué git reset NUNCA se usa sobre commits ya públicos, y qué se usa en su lugar?","options":["Porque reset es lento; se usa restore","Porque reset MUEVE/REESCRIBE la historia: hacerlo sobre commits que otros ya tienen deja historiales divergentes — para deshacer algo público se usa revert (que solo agrega un commit)","Porque reset borra el remoto; se usa clone","No hay problema en usar reset sobre lo público"],"correctIndex":1,"feedback":{"correct":"Correcto. reset reescribe (solo local); revert conserva (público). Usar reset sobre lo compartido rompe la regla de oro.","incorrect":"reset reescribe la historia: sobre lo público rompe los historiales del equipo. Para deshacer algo compartido, revert."}}$j$),
  (9, 'resumen', $j${"title":"Resumen — reset y la tabla imprescindible","points":["git reset mueve el puntero de la rama a un commit anterior (deshace commits): herramienta LOCAL.","--soft: historial atrás, cambios PREPARADOS · --mixed (defecto): historial atrás, cambios SIN preparar · --hard: historial atrás, cambios BORRADOS.","Solo --hard pierde trabajo (el reflog aún rescata lo que fue commit; nada más).","reset REESCRIBE la historia → nunca sobre commits públicos; para eso está revert (que solo agrega un commit).","La frase: reset reorganiza lo tuyo antes de compartir; revert corrige lo ya compartido."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-l03-reset';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · Recuperar trabajo con reflog
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La red de seguridad secreta","body":"'Hice git reset --hard y borré un commit que sí necesitaba. ¿Lo perdí?' Casi siempre, NO — y esta lección es la que quita el pánico. Git lleva, además del historial, una BITÁCORA PRIVADA de todos los movimientos de tus punteros: cada vez que HEAD se mueve (un commit, un cambio de rama, un merge, un reset…), queda registrado en el REFLOG (reference log, el registro de referencias). git reflog te muestra esa lista: dónde estuvo HEAD en cada paso reciente, con su hash. Y aquí está la magia: aunque un commit ya no aparezca en ningún git log (porque un reset movió el puntero y lo dejó 'huérfano'), su hash SIGUE en el reflog — y si tienes el hash, puedes volver a él. El reflog es el 'historial de tu historial', la red bajo el trapecista."}$j$),
  (2, 'ejemplo_codigo', $j${"title":"Rescatar un commit tras un reset","code":"# Uy: reset --hard borro un commit que necesitaba\ngit reflog\n#   e5f6g7h HEAD@{0}: reset: moving to HEAD~1\n#   a3f9c1d HEAD@{1}: commit: Trabajo importante   <- este!\n#   b2c3d4e HEAD@{2}: commit: Modulo de facturas\n\n# El commit sigue vivo: creo una rama de rescate sobre su hash\ngit switch -c rescate a3f9c1d","caption":"El reflog conserva el hash del commit 'perdido'. Con el hash, una rama de rescate lo trae de vuelta.","result":{"columns":["RESULTADO"],"rows":[["Switched to a new branch 'rescate'"],["(el commit a3f9c1d y su trabajo, de vuelta y a salvo)"]],"note":"El commit nunca desapareció de verdad: el reset solo movió el puntero, dejándolo huérfano. El reflog guardó su hash, y crear una rama sobre ese hash lo rescató. La mejor red de seguridad de Git."}}$j$),
  (3, 'texto', $j${"title":"Sus tres límites (que hay que respetar)","body":"El reflog es poderoso, pero tiene fronteras claras que impiden confiarle demasiado. UNO: es LOCAL — registra los movimientos de TU repositorio, en TU máquina; no viaja al remoto ni existe para nadie más. Lo que borres en tu equipo, el reflog de tu equipo puede rescatarlo, pero no hay un reflog compartido. DOS: NO es un respaldo — es una comodidad de recuperación reciente, no un sistema de copias de seguridad; para eso están los remotos y los backups de verdad. TRES: sus entradas EXPIRAN — Git las limpia con el tiempo (por defecto, semanas), así que el reflog rescata lo que 'perdiste' hace poco, no lo de hace meses. Conclusión práctica: el reflog es tu red para el error reciente ('acabo de hacer un reset tonto'), no un archivo eterno. Sabiendo que existe, casi ningún reset o rebase local da miedo — pero no lo trates como respaldo."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué es el reflog y para qué sirve?","options":["Una copia de seguridad en la nube","Una bitácora LOCAL de todos los movimientos de tus punteros (HEAD): conserva los hashes de commits recientes aunque un reset los deje huérfanos, permitiendo recuperarlos","El historial de commits normal","Un registro de los remotos"],"correctIndex":1,"feedback":{"correct":"Correcto. El reflog es el 'historial de tu historial': la red que rescata commits que un reset dejó fuera del log.","incorrect":"El reflog registra los movimientos de HEAD y guarda hashes recientes: permite recuperar commits huérfanos tras un reset. No es un respaldo en la nube."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Hiciste git reset --hard y perdiste un commit importante. ¿Cómo lo recuperas?","options":["Es imposible, se perdió","git reflog para encontrar su hash (sigue registrado aunque ya no aparezca en git log) y luego crear una rama de rescate sobre ese hash (git switch -c rescate HASH)","git pull del remoto","git restore"],"correctIndex":1,"feedback":{"correct":"Correcto. El commit sigue vivo con su hash en el reflog: una rama de rescate sobre ese hash lo trae de vuelta.","incorrect":"El reflog conserva el hash del commit huérfano: lo buscas ahí y creas una rama sobre él. reset movió el puntero, no destruyó el commit."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuáles son los límites del reflog que impiden tratarlo como respaldo?","options":["No tiene límites","Es LOCAL (solo tu máquina, no viaja al remoto), NO es un respaldo (es recuperación reciente), y sus entradas EXPIRAN con el tiempo — rescata lo que perdiste hace poco, no hace meses","Solo funciona en GitHub","Requiere permisos de administrador"],"correctIndex":1,"feedback":{"correct":"Correcto. Local, no-respaldo, y expira: es una red para el error reciente, no un archivo eterno ni compartido.","incorrect":"El reflog es local, no es un backup y sus entradas caducan. Sirve para el 'reset tonto de hace un rato', no para recuperar lo de hace meses."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — reflog","points":["El reflog es una bitácora LOCAL de todos los movimientos de HEAD (commits, cambios de rama, merges, resets).","Conserva los hashes de commits recientes aunque un reset los deje huérfanos (fuera de git log).","Recuperación: git reflog → encontrar el hash → git switch -c rescate HASH.","Tres límites: es LOCAL (no viaja al remoto), NO es un respaldo, y sus entradas EXPIRAN (semanas).","Sabiendo que existe, los reset/rebase LOCALES dejan de dar miedo — pero no es un sistema de copias de seguridad."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-l04-reflog';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · Encontrar el error con bisect
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"'Funcionaba la semana pasada'","body":"El diagnóstico más frustrante: algo que funcionaba se rompió, pero no sabes qué commit lo rompió — y hay 200 commits entre la última versión buena y ahora. Revisarlos uno por uno es una tortura. git bisect convierte esa búsqueda en algo casi mágico usando BÚSQUEDA BINARIA: en vez de revisar los 200 commits en orden, va partiendo el rango a la mitad. Le dices a Git un commit que SABES que estaba bien ('good') y uno que SABES que está mal ('bad', normalmente el actual); Git te lleva al commit de EN MEDIO y te pregunta '¿aquí ya está el error?'. Según tu respuesta, descarta la mitad del rango y repite. 200 commits se reducen a unas 8 preguntas (cada respuesta corta el rango a la mitad): log2(200) ≈ 8. Es encontrar una aguja en el pajar preguntando '¿está en esta mitad?' hasta que solo queda una."}$j$),
  (2, 'ejemplo_codigo', $j${"title":"Cazar el commit culpable","code":"# Iniciar la busqueda\ngit bisect start\n\n# El commit actual esta MAL\ngit bisect bad\n\n# Un commit que sabemos BUENO (p. ej. el tag de la version pasada)\ngit bisect good v1.2.0\n\n# Git te lleva al commit de en medio. Lo pruebas y respondes:\ngit bisect good   # si aqui todavia funcionaba\n# ...o...\ngit bisect bad    # si aqui ya estaba roto\n\n# Repites hasta que Git anuncia el culpable, y terminas:\ngit bisect reset","caption":"start → bad → good → (probar y responder good/bad varias veces) → Git señala el commit culpable → reset para terminar.","result":{"columns":["RESULTADO"],"rows":[["Bisecting: 100 revisions left to test after this (roughly 7 steps)"],["... (respondes good/bad en cada paso) ..."],["a3f9c1d is the first bad commit"],["  Cambia la formula del total"]],"note":"En ~7 pasos, de 200 commits sospechosos a UNO: 'a3f9c1d is the first bad commit'. Ahora sabes exactamente qué cambio introdujo el error y por qué. git bisect reset te devuelve a donde estabas antes de empezar."}}$j$),
  (3, 'texto', $j${"title":"Por qué esto vale oro (y por qué los commits atómicos ayudan)","body":"bisect es diagnóstico puro: no arregla nada, te dice DÓNDE está el problema — y saber qué commit introdujo un error es la mitad de resolverlo, porque ese commit trae consigo su mensaje (qué se intentaba), su diff (qué cambió exactamente) y su contexto (la incidencia que lo motivó). De pronto un bug misterioso tiene autor, fecha y motivo. Y aquí se cierra un círculo del curso: bisect funciona MUCHO mejor sobre un historial de COMMITS ATÓMICOS (módulo 2). Si cada commit hace una sola cosa, cuando bisect señale al culpable, el diff será pequeño y el problema, evidente. Si los commits son basureros de cinco cambios mezclados, bisect te llevará al commit correcto… pero tendrás que bucear entre cinco cosas para hallar cuál rompió. Cada práctica del curso se sostiene: los commits limpios que aprendiste a hacer en el módulo 2 son los que hacen que el diagnóstico del módulo 5 sea rápido."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué problema resuelve git bisect y cómo?","options":["Arregla los errores automáticamente","ENCUENTRA el commit que introdujo un error usando BÚSQUEDA BINARIA: parte el rango a la mitad en cada paso, así 200 commits se reducen a ~8 preguntas","Borra los commits malos","Crea una rama de prueba"],"correctIndex":1,"feedback":{"correct":"Correcto. bisect localiza al culpable por búsqueda binaria: log2(n) pasos. No arregla, diagnostica.","incorrect":"bisect no arregla: encuentra el commit culpable partiendo el rango a la mitad cada vez (búsqueda binaria). 200 commits → ~8 preguntas."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es el flujo básico de git bisect?","options":["bisect run y esperar","git bisect start → git bisect bad (el commit actual roto) → git bisect good HASH (uno que funcionaba) → probar y responder good/bad en cada paso → Git señala el culpable → git bisect reset","bisect good → bisect delete","git bisect find"],"correctIndex":1,"feedback":{"correct":"Correcto. start, marcas un bad y un good, respondes en cada paso, Git converge al culpable, y reset para salir.","incorrect":"El flujo: start → marcar bad y good → responder good/bad en cada commit intermedio → culpable → reset. Le das los extremos y Git te guía."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué los COMMITS ATÓMICOS (módulo 2) hacen que bisect sea más útil?","options":["No tienen relación","Porque cuando bisect señala al commit culpable, si ese commit hace UNA sola cosa su diff es pequeño y el error es evidente — con commits basureros de cinco cambios, tendrías que bucear entre todos para hallar cuál rompió","Porque bisect solo funciona con commits atómicos","Porque los hacen más rápidos de crear"],"correctIndex":1,"feedback":{"correct":"Correcto. El diagnóstico se paga con la calidad del historial: commit atómico = culpable con diff pequeño y claro.","incorrect":"bisect funciona con cualquier historial, pero un commit atómico culpable tiene un diff pequeño y evidente. Los commits mezclados esconden el error entre varios cambios."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — bisect","points":["git bisect ENCUENTRA el commit que introdujo un error mediante BÚSQUEDA BINARIA (parte el rango a la mitad).","Reduce cientos de commits a ~log2(n) preguntas: 200 → ~8 pasos.","Flujo: start → bad (actual) → good HASH (versión buena) → responder good/bad en cada paso → culpable → reset.","Es diagnóstico, no arreglo: pero conocer el commit culpable (con su mensaje, diff y contexto) es media solución.","Brilla sobre COMMITS ATÓMICOS: el culpable trae un diff pequeño y evidente. El módulo 2 paga en el módulo 5."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-l05-bisect';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · Práctica: incidente en producción (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"Eres quien está de guardia y llegan cinco situaciones distintas. Para cada una, elige la HERRAMIENTA de recuperación correcta. El caso 1 viene resuelto de ejemplo; completa los demás con la respuesta exacta (en minúsculas, tal como aparece en las opciones de cada caso).","instructions":["Caso 2 — Un commit que YA está en main (compartido) rompió el cálculo de facturas en producción. ¿Cómo lo deshaces sin reescribir la historia? (revert / reset / restore)","Caso 3 — Editaste un archivo, no lo has commiteado, y quieres descartar ese cambio no confirmado. ¿Qué usas? (revert / reset / restore)","Caso 4 — Hiciste un reset --hard local y borraste un commit que sí necesitabas; quieres recuperarlo. ¿Qué consultas para encontrar su hash? (reflog / bisect / status)","Caso 5 — Algo se rompió en algún punto de los últimos 150 commits y no sabes cuál lo causó. ¿Qué herramienta encuentra el commit culpable? (reflog / bisect / revert)"],"initialCode":"# HOJA DE GUARDIA — incidentes de recuperacion\n\n# Caso 1 (ejemplo): tres commits LOCALES que quiero rearmar\n#   como uno, sin perder trabajo -> reset --soft\ncaso1_herramienta=reset\n\n# Caso 2: commit ya en main rompio produccion\ncaso2_herramienta=?\n\n# Caso 3: descartar un cambio NO confirmado\ncaso3_herramienta=?\n\n# Caso 4: recuperar un commit tras reset --hard\ncaso4_herramienta=?\n\n# Caso 5: hallar el commit que introdujo un bug\ncaso5_herramienta=?","validators":["caso2_herramienta\\s*=\\s*revert\\b","caso3_herramienta\\s*=\\s*restore\\b","caso4_herramienta\\s*=\\s*reflog\\b","caso5_herramienta\\s*=\\s*bisect\\b"],"mockOutput":{"columns":["CASO","HERRAMIENTA","POR QUÉ"],"rows":[["1 · rearmar commits locales","reset --soft","mueve el puntero conservando los cambios preparados; es LOCAL"],["2 · commit público roto","revert","deshace con un commit nuevo sin reescribir la historia compartida"],["3 · cambio no confirmado","restore","descarta lo no commiteado (lo que nunca fue commit)"],["4 · recuperar tras --hard","reflog","conserva el hash del commit huérfano para rescatarlo"],["5 · hallar el culpable","bisect","búsqueda binaria: de 150 commits a ~8 preguntas"]],"note":"Cinco incidentes, cinco herramientas: cada arrepentimiento tiene la suya. La regla maestra: público → revert (no reescribe); local → reset (reescribe); no confirmado → restore; recuperar lo borrado → reflog; diagnosticar → bisect."},"hints":["Caso 2: 'ya está en main / compartido / sin reescribir la historia' apunta a la herramienta que solo AGREGA un commit inverso.","Caso 3: 'no confirmado / no commiteado' es territorio de restore. Caso 4: el 'historial de tu historial' que guarda los hashes huérfanos.","Caso 5: 'no sé cuál de 150 commits' pide una búsqueda binaria que encuentra al culpable."],"successMessage":"¡Guardia superada! Elegiste la herramienta correcta para cada arrepentimiento: revert para lo público (sin reescribir), restore para lo no confirmado, reflog para rescatar lo borrado y bisect para diagnosticar. Esa es la diferencia entre entrar en pánico y resolver: Git tiene una salida segura para cada situación.","failMessage":"Revisa la regla maestra: caso2=revert (público, no reescribe) · caso3=restore (cambio no confirmado) · caso4=reflog (recuperar el commit huérfano) · caso5=bisect (encontrar el culpable por búsqueda binaria)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-l06-practica';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La quinta región","body":"Byte aprende a caerse sin lastimarse. Once preguntas guardan esta región: restore, revert, los tres reset, el reflog y bisect — cada arrepentimiento con su herramienta segura. Las que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Editaste un archivo, no lo commiteaste, y quieres descartar ese cambio. ¿Qué usas?","options":["git revert archivo","git restore archivo — descarta el cambio no confirmado, devolviendo el archivo al último commit","git reset --hard","git bisect"],"correctIndex":1,"feedback":{"correct":"Correcto. restore (sin --staged) descarta lo no confirmado. revert es para commits; bisect diagnostica.","incorrect":"Lo no confirmado se descarta con git restore. revert deshace commits ya hechos; no aplica aquí."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué git restore archivo (sin --staged) es irreversible?","options":["Porque borra el repositorio","Porque descarta cambios que nunca estuvieron en un commit: Git no tiene copia de ellos (ni el reflog los salva) — por eso se revisa git status/diff antes","Porque bloquea la rama","No es irreversible"],"correctIndex":1,"feedback":{"correct":"Correcto. Lo no commiteado no tiene respaldo en Git: descartarlo es definitivo.","incorrect":"restore descarta trabajo del que Git no guarda copia: es una puerta de un solo sentido. Mira el estado antes."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Un commit YA en main (compartido) rompió producción. ¿Cómo lo deshaces de forma segura?","options":["git reset --hard para borrarlo","git revert HASH: crea un commit NUEVO que lo anula sin reescribir la historia — seguro en un repositorio compartido","git restore","git commit --amend"],"correctIndex":1,"feedback":{"correct":"Correcto. Público → revert: deshace con un commit inverso, sin tocar la historia que otros tienen.","incorrect":"Sobre lo compartido, revert. reset o amend reescribirían la historia del equipo: la regla de oro rota."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué hace git revert con el historial?","options":["Lo encoge borrando el commit malo","Lo hace CRECER: agrega un commit que deshace al malo; el commit original sigue visible — 'deshacer hacia adelante'","Lo reescribe","No lo toca"],"correctIndex":1,"feedback":{"correct":"Correcto. revert suma un commit inverso; nada se borra. Por eso es seguro en lo compartido.","incorrect":"revert agrega un commit que anula al malo (el historial crece). No borra ni reescribe: por eso sirve para lo público."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Los tres modos de git reset (--soft/--mixed/--hard) tienen en común que…","options":["Los tres borran archivos","Los tres MUEVEN el puntero de la rama a un commit anterior (deshacen commits); se diferencian en qué pasa con los cambios (preparados/sin preparar/borrados)","Los tres crean un commit","Los tres son seguros en lo público"],"correctIndex":1,"feedback":{"correct":"Correcto. Constante: mover el puntero atrás. Variable: soft (preparados), mixed (sin preparar), hard (borrados).","incorrect":"Los tres mueven el puntero (deshacen commits). Difieren en el destino de los cambios, no en si crean commits."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"Quieres deshacer 3 commits LOCALES para rearmarlos como uno, sin perder trabajo. ¿Qué modo de reset?","options":["--hard","--soft: mueve el puntero atrás y deja los cambios PREPARADOS, listos para recommitear","--mixed","Ninguno; usa revert"],"correctIndex":1,"feedback":{"correct":"Correcto. --soft conserva todo preparado: ideal para recombinar commits locales.","incorrect":"--soft deja los cambios listos para rehacer el commit. --hard los borraría; revert no reorganiza."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál modo de reset puede hacerte perder trabajo?","options":["--soft","--hard: descarta los cambios de los commits deshechos del directorio — el reflog aún rescata lo que fue commit, pero conviene mirar git status antes","--mixed","Ninguno"],"correctIndex":1,"feedback":{"correct":"Correcto. Solo --hard destruye trabajo; soft y mixed lo conservan. Revisa el estado antes.","incorrect":"El filoso es --hard (borra trabajo). soft y mixed conservan los cambios. Precaución: git status antes."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"Hiciste git reset --hard y perdiste un commit importante. ¿Cómo lo recuperas?","options":["Es imposible","git reflog para hallar su hash (sigue registrado aunque no salga en git log) y crear una rama de rescate sobre él — el reset movió el puntero, no destruyó el commit","git pull","git restore"],"correctIndex":1,"feedback":{"correct":"Correcto. El reflog guarda el hash del commit huérfano: una rama de rescate lo trae de vuelta.","incorrect":"El reflog conserva el hash del commit tras el reset: lo buscas ahí y creas una rama. No está perdido."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuáles son los límites del reflog?","options":["No tiene límites, es un respaldo total","Es LOCAL (no viaja al remoto), NO es un respaldo, y sus entradas EXPIRAN con el tiempo — rescata errores recientes, no de hace meses","Solo funciona en GitHub","Requiere ser administrador"],"correctIndex":1,"feedback":{"correct":"Correcto. Local, no-respaldo y caduca: una red para el error reciente, no un archivo eterno.","incorrect":"El reflog es local, no es backup y expira. Sirve para el 'reset tonto de hace un rato', no como sistema de copias."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"Algo se rompió en algún punto de los últimos 150 commits y no sabes cuál. ¿Qué herramienta lo encuentra, y cómo?","options":["git reflog, revisando todo","git bisect: por BÚSQUEDA BINARIA parte el rango a la mitad en cada paso (le das un commit bueno y uno malo) y reduce 150 commits a ~8 preguntas hasta señalar al culpable","git revert, uno por uno","git status"],"correctIndex":1,"feedback":{"correct":"Correcto. bisect encuentra al culpable por búsqueda binaria: log2(150) ≈ 8 pasos. Diagnóstico, no arreglo.","incorrect":"git bisect localiza el commit culpable partiendo el rango a la mitad. reflog recupera; revert deshace; bisect diagnostica."}}$j$),
  (12, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta de cierre: la regla maestra de este módulo distingue las herramientas por DÓNDE está el problema. Ordénalas: cambio no confirmado / commit local a reorganizar / commit público a deshacer.","options":["reset / revert / restore","restore (lo no confirmado, se descarta) / reset (lo local, reescribe la historia privada) / revert (lo público, deshace con un commit sin reescribir)","revert / restore / reset","Las tres hacen lo mismo"],"correctIndex":1,"feedback":{"correct":"Impecable. restore para lo no confirmado, reset para reorganizar lo local, revert para deshacer lo público. Y reflog rescata, bisect diagnostica. Cada arrepentimiento, su herramienta segura.","incorrect":"Por dónde está el problema: no confirmado → restore; local a reorganizar → reset (reescribe); público a deshacer → revert (no reescribe). Esa es la regla maestra."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm05-x01-examen';
